import React from 'react';
import { Outlet, Link, Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

// Icons SVG Minimalist
const Icons = {
  Staff: ({ active }) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active ? "#003366" : "#888"} strokeWidth="2"><path d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>,
  Task: ({ active }) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active ? "#003366" : "#888"} strokeWidth="2"><path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" /></svg>,
  Discipline: ({ active }) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active ? "#003366" : "#888"} strokeWidth="2"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>,
  Report: ({ active }) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active ? "#003366" : "#888"} strokeWidth="2"><path d="M16 8v8m-4-5v5m-4-2v2m-2 4h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
};

const AdminLayout = () => {
  const { user, logout } = useAuth();
  const location = useLocation();

  if (!user || !['chief', 'reg', 'op'].includes(user.role)) return <Navigate to="/" />;

  const isActive = (path) => location.pathname === path;

  const linkStyle = (path) => ({
    textDecoration: 'none',
    color: isActive(path) ? '#003366' : '#666',
    fontWeight: isActive(path) ? 'bold' : '500',
    display: 'flex', alignItems: 'center', gap: '12px', padding: '12px 15px',
    borderRadius: '8px',
    background: isActive(path) ? '#e6f7ff' : 'transparent',
    transition: 'all 0.2s',
    marginBottom: '5px'
  });

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', background: '#f5f7fa' }}>
      
      {/* HEADER: White Background, Fixed, Transparent Logo */}
      <header style={{ 
          background: '#ffffff', 
          color: '#003366', 
          padding: '0 20px', 
          height: '65px', 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          boxShadow: '0 2px 4px rgba(0,0,0,0.08)', 
          position: 'sticky', 
          top: 0, 
          zIndex: 1000 
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          {/* Logo Transparent */}
          <img src="/BA LOGO.png" alt="Be Able VN Logo" style={{ height: '45px', objectFit: 'contain' }} />
          <div>
            <h1 style={{ margin: 0, fontSize: '1.2rem', fontWeight: 'bold' }}>Be Able VN</h1>
            <span style={{ fontSize: '0.75rem', color: '#666', textTransform: 'uppercase', letterSpacing: '0.5px' }}>{user.role} Admin</span>
          </div>
        </div>
        <button onClick={logout} style={{ border: '1px solid #003366', background: 'transparent', color: '#003366', padding: '6px 15px', borderRadius: '4px', cursor: 'pointer', fontWeight: '500' }}>Đăng xuất</button>
      </header>

      <div style={{ display: 'flex', flex: 1, maxWidth: '1400px', width: '100%', margin: '0 auto' }}>
        
        {/* Sidebar (Desktop) */}
        <aside style={{ width: '250px', background: '#fff', padding: '20px', borderRight: '1px solid #eee', display: 'none' }} className="desktop-sidebar">
          <nav>
            <Link to="/admin/staff-manager" style={linkStyle('/admin/staff-manager')}>
              <Icons.Staff active={isActive('/admin/staff-manager')} /> Quản lý Nhân sự
            </Link>
            
            {(user.role === 'op' || user.role === 'chief') && (
              <Link to="/admin/task-manager" style={linkStyle('/admin/task-manager')}>
                <Icons.Task active={isActive('/admin/task-manager')} /> Điều phối & Giao việc
              </Link>
            )}

            {(user.role === 'reg' || user.role === 'chief') && (
              <Link to="/admin/discipline-manager" style={linkStyle('/admin/discipline-manager')}>
                <Icons.Discipline active={isActive('/admin/discipline-manager')} /> Quy chế & Duyệt
              </Link>
            )}

            <Link to="/admin/reports" style={linkStyle('/admin/reports')}>
              <Icons.Report active={isActive('/admin/reports')} /> Báo cáo tổng hợp
            </Link>
          </nav>
        </aside>

        {/* Main Content */}
        <main style={{ flex: 1, padding: '20px', overflowX: 'hidden' }}>
          <Outlet />
        </main>
      </div>

      <style>{`
        .desktop-sidebar { display: block !important; }
        @media (max-width: 768px) {
          .desktop-sidebar { display: none !important; }
        }
      `}</style>
    </div>
  );
};

export default AdminLayout;
